// Debounce: ждём паузу в 300ms после последнего ввода
function debounce(fn, delay) {
  let timeoutId;
  return function(...args) {
    clearTimeout(timeoutId);
    timeoutId = setTimeout(() => fn.apply(this, args), delay);
  };
}

searchInput.addEventListener('input', debounce((e) => {
  api.search(e.target.value); // вызовется только после остановки печати
}, 300));

// Throttle: выполняем не чаще раза в 100ms
function throttle(fn, limit) {
  let inThrottle;
  return function(...args) {
    if (!inThrottle) {
      fn.apply(this, args);
      inThrottle = true;
      setTimeout(() => inThrottle = false, limit);
    }
  };
}

window.addEventListener('scroll', throttle(() => {
  checkInfiniteScroll(); // не чаще 100ms
}, 100));

// Modern: requestAnimationFrame для throttle
function rafThrottle(fn) {
  let ticking = false;
  return (...args) => {
    if (!ticking) {
      window.requestAnimationFrame(() => {
        fn(...args);
        ticking = false;
      });
      ticking = true;
    }
  };
}

