// useMemo - кэшируем результат вычислений
function Dashboard({ items, filter }) {
  const filteredItems = useMemo(() => {
    return items.filter(filter); // O(n) операция
  }, [items, filter]); // только если items/filter изменились

  return <List items={filteredItems} />;
}

// useCallback - кэшируем функцию
function Parent() {
  const [count, setCount] = useState(0);

  // ❌ Без useCallback: новая функция каждый рендер
  const handleClick = () => console.log('clicked');

  // ✅ С useCallback: та же ссылка
  const handleClick = useCallback(() => {
    console.log('clicked');
  }, []); // зависимости

  return <Child onClick={handleClick} />; // Child не будет лишний раз рендериться
}

