// Метрики (Core Web Vitals):
// LCP < 2.5s (Largest Contentful Paint)
// FID < 100ms (First Input Delay)
// CLS < 0.1 (Cumulative Layout Shift)

// ❌ ПЛОХО: Forced Synchronous Layout
function updatePositions() {
  const boxes = document.querySelectorAll('.box');
  boxes.forEach(box => {
    const width = box.offsetWidth; // Читаем (Reflow!)
    box.style.width = width * 2 + 'px'; // Пишем (Reflow!)
    // Каждая итерация заставляет браузер пересчитывать!
  });
}

// ✅ ХОРОШО: Batch операции
function updatePositions() {
  const boxes = document.querySelectorAll('.box');

  // Сначала читаем всё
  const widths = Array.from(boxes).map(box => box.offsetWidth);

  // Потом пишем всё
  boxes.forEach((box, i) => {
    box.style.width = widths[i] * 2 + 'px';
  });
}

// ✅ Анимации только с transform/opacity (Composite layer)
